const exams = $input.first().json;
const today = new Date();
const thirtyDays = new Date(today.getTime() + 30 * 24 * 60 * 60 * 1000);

// Pick exams that need verification:
// 1. Last date within 30 days
// 2. Never verified or not verified in 7+ days
const needsCheck = exams.filter(e => {
  const lastDate = new Date(e.lastDate);
  const lastVerified = e.lastVerifiedAt ? new Date(e.lastVerifiedAt) : null;
  const daysSinceVerified = lastVerified ? Math.floor((today - lastVerified) / (86400000)) : 999;
  return (lastDate > today && lastDate <= thirtyDays && daysSinceVerified >= 7) || daysSinceVerified >= 14;
}).slice(0, 10); // Process max 10 per run to stay within API limits

return needsCheck.map(e => ({ json: e }));

