parameters.jsCode:
const examTitle = $('Filter Exams Needing Verification').item.json.title;
const examCategory = $('Filter Exams Needing Verification').item.json.category;
const aiResponse = $input.first().json;

try {
  const text = aiResponse.candidates[0].content.parts[0].text;
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (!jsonMatch) return [{ json: { skip: true, title: examTitle, reason: 'No JSON in AI response' } }];

  const result = JSON.parse(jsonMatch[0]);

  if (!result.needsUpdate) {
    return [{ json: { skip: true, title: examTitle, notes: result.notes || 'Verified correct' } }];
  }

  const updates = {};
  if (result.lastDate) updates.lastDate = result.lastDate;
  if (result.vacancies) updates.vacancies = result.vacancies;
  if (result.isActive !== null && result.isActive !== undefined) updates.isActive = result.isActive;

  return [{ json: {
    skip: false,
    title: examTitle,
    category: examCategory,
    updates,
    notes: result.notes,
    source: 'n8n-ai-verifier-gemini'
  }}];
} catch (e) {
  return [{ json: { skip: true, title: examTitle, reason: 'Parse error: ' + e.message } }];
}

